Use Object.getPrototypeOf() repeatedly: <code>let proto = Object.getPrototypeOf(obj);
while (proto) {
  console.log(proto.constructor.name);
  proto = Object.getPrototypeOf(proto);
}</code> The deprecated __proto__ property also works but is not recommended.

codeExamples.code:
const grandparent = { a: 1 };
const parent = Object.create(grandparent);
parent.b = 2;
const child = Object.create(parent);
child.c = 3;

function walkChain(obj) {
  let proto = obj;
  let depth = 0;
  while (proto) {
    const own = Object.keys(proto);
    console.log(`Level ${depth}:`, own.length ? own : '[no own props]');
    proto = Object.getPrototypeOf(proto);
    depth++;
  }
  console.log('Chain ends at null');
}

walkChain(child);
// Level 0: ['c']
// Level 1: ['b']
// Level 2: ['a']
// Level 3: [no own props]  (Object.prototype)
// Chain ends at null

function Animal() {}
function Dog() {}

// Set up inheritance: Dog.prototype inherits from Animal.prototype
Dog.prototype = Object.create(Animal.prototype);
Dog.prototype.constructor = Dog;

const d = new Dog();

console.log(d instanceof Dog);    // true
console.log(d instanceof Animal); // true
console.log(d instanceof Object); // true
console.log(d instanceof Array);  // false

// instanceof walks d's prototype chain looking for Constructor.prototype

function User(name) {
  this.name = name;
}

const u1 = new User('Alice');
const u2 = new User('Bob');

// Add method after instances exist
User.prototype.sayHi = function() {
  return `Hi, I'm ${this.name}`;
};

console.log(u1.sayHi()); // 'Hi, I'm Alice' (works!)
console.log(u2.sayHi()); // 'Hi, I'm Bob' (works!)

// Even works on pre-existing instances via prototype chain lookup

const base = { version: '1.0', getVersion() { return this.version; } };
const extended = Object.create(base);

console.log(extended.getVersion()); // '1.0' (inherited)

extended.version = '2.0'; // shadowing
console.log(extended.getVersion()); // '2.0' (own property used)
console.log(base.version);          // '1.0' (unaffected)

delete extended.version;
console.log(extended.getVersion()); // '1.0' (inherited again)

const arr = [1, 2, 3];

console.log(Object.getPrototypeOf(arr) === Array.prototype);   // true
console.log(Object.getPrototypeOf(Array.prototype) === Object.prototype); // true
console.log(Object.getPrototypeOf(Object.prototype)); // null

// Chain: arr → Array.prototype → Object.prototype → null

const fn = function() {};
console.log(Object.getPrototypeOf(fn) === Function.prototype); // true
// Chain: fn → Function.prototype → Object.prototype → null

const str = 'hello';
// Strings get auto-boxed: str → String.prototype → Object.prototype → null
